        # --- Left: model list ---
        left = QtWidgets.QVBoxLayout()
        left.setSpacing(4)
        list_label = QtWidgets.QLabel("Custom Models")
        list_label.setStyleSheet("font-weight: bold; font-size: 12px; color: #fff;")
